SELECT COUNT(DISTINCT player_id) AS total_players
FROM team_rosters
WHERE tournament_id = 1;

SELECT COUNT(DISTINCT player_id) AS active_players_count
FROM team_rosters
WHERE tournament_id = 1 AND is_active = 1;

SELECT COUNT(score) AS total_scores
FROM team_scores
WHERE team_id = 1 AND tournament_id = 1;

SELECT total_score 
FROM tournament_standings 
WHERE tournament_id = 1;

SELECT COUNT(*) AS active_players_count
FROM team_rosters
WHERE is_active = 1 AND tournament_id = 1;

SELECT team_id, round_number, MAX(score) AS max_score
FROM team_scores
GROUP BY team_id, round_number;

SELECT COUNT(*) AS total_transfers
FROM player_transfers
WHERE team_id = 123;
